import { useEffect } from "react";
import API from "../api/axios";

function Dashboard() {

  useEffect(() => {
    API.get("/dashboard")
      .then(res => console.log(res.data))
      .catch(err => console.log(err));
  }, []);

  return <h2>Dashboard</h2>;
}

export default Dashboard;
